import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e as t}from"./app-76b20676.js";const e={},p=t(`<h2 id="_1-타입-변환이란" tabindex="-1"><a class="header-anchor" href="#_1-타입-변환이란" aria-hidden="true">#</a> 1. 타입 변환이란?</h2><p>개발자가 의도적으로 값의 타입을 변환하는 것을 <strong>명시적(Explicit) 타입 변환</strong><br> 또는 <strong>타입 캐스팅</strong>이라 한다</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>

<span class="token keyword">var</span> str <span class="token operator">=</span> x<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> str<span class="token punctuation">,</span> str<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// string 10</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> x<span class="token punctuation">,</span> x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//number 10</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>개발자의 의도와는 상관 없이 표현식을 평가하는 도중에 암묵적으로 타입이 자동 변환 되기도 한다.</p><p>이를 <strong>암묵적(Implicit) 타입 변환</strong> 또는 <strong>타입 강제 변환</strong>이라 한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>

<span class="token keyword">var</span> str <span class="token operator">=</span> x <span class="token operator">+</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> str<span class="token punctuation">,</span> str<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//string 10</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">typeof</span> x<span class="token punctuation">,</span> x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//number 10</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_2-암묵적-타입-변환" tabindex="-1"><a class="header-anchor" href="#_2-암묵적-타입-변환" aria-hidden="true">#</a> 2. 암묵적 타입 변환</h2><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 피연산자가 모두 문자열 타입이어야 하는 문맥</span>
<span class="token string">&quot;10&quot;</span> <span class="token operator">+</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; &#39;102&#39;</span>

<span class="token comment">//피연산자가 모두 숫자 타입이어야 하는 문맥</span>
<span class="token number">5</span> <span class="token operator">*</span> <span class="token string">&quot;10&quot;</span><span class="token punctuation">;</span> <span class="token comment">// -&gt; 50</span>

<span class="token comment">//피연산자 또는 표현식이 불리언 타입이어야 하는 문맥</span>
<span class="token operator">!</span><span class="token number">0</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>표현식을 평가할 때 코드의 문맥에 부합하지 않는 다양한 상황이 발생할 수 있다.<br> 타입별로 암묵적 타입 변환이 어떻게 발생하는지 살펴보자.</p><h3 id="_2-1-문자열-타입으로-변환" tabindex="-1"><a class="header-anchor" href="#_2-1-문자열-타입으로-변환" aria-hidden="true">#</a> 2.1. 문자열 타입으로 변환</h3><p>자바스크립트 엔진은 표현식을 평가할 때 코드 문맥에 부합하도록 암묵적 타입 변환을 실행한다.<br> 예를 들어, ES6에서 도입된 템플릿 리터럴 표현식 삽입은 표현식의 평가 결과를 문자열 타입으로 변환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">1 + 1 = </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span><span class="token number">1</span> <span class="token operator">+</span> <span class="token number">1</span><span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &quot;1 + 1 = 2&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>문자열 타입이 아닌 값을 문자열 타입으로 암묵적 타입 변환을 수행할 때 다음과 같이 동작한다</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 숫자 타입</span>
<span class="token number">0</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">//-&gt; &quot;0&quot;</span>
<span class="token operator">-</span><span class="token number">0</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">//-&gt; &quot;0&quot;</span>
<span class="token operator">-</span><span class="token number">1</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">//-&gt; &quot;-1&quot;</span>
<span class="token number">NaN</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">//-&gt; &quot;NaN&quot;</span>
<span class="token operator">-</span><span class="token number">Infinity</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">//-&gt; &quot;-Infinity&quot;</span>

<span class="token comment">// 불리언 타입</span>
<span class="token boolean">true</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">//-&gt; &quot;true&quot;</span>
<span class="token boolean">false</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">//-&gt; &quot;false&quot;</span>

<span class="token comment">// null 타입</span>
<span class="token keyword">undefined</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">//-&gt; &quot;undefined&quot;</span>

<span class="token comment">// 객체 타입</span>
<span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">// -&gt; &quot;[object Object]&quot;</span>
Math <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">// -&gt; &quot;[object Math]&quot;</span>
<span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">// -&gt; &quot;&quot;</span>
<span class="token punctuation">[</span><span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">]</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">//-&gt; &quot;10, 20&quot;</span>
<span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">//-&gt; &quot;function(){}&quot;</span>
Array <span class="token operator">+</span> <span class="token string">&#39;&#39;</span> <span class="token comment">//-&gt; &quot;function Array() {[native code]}&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-2-숫자-타입으로-변환" tabindex="-1"><a class="header-anchor" href="#_2-2-숫자-타입으로-변환" aria-hidden="true">#</a> 2.2. 숫자 타입으로 변환</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token number">1</span> <span class="token operator">-</span> <span class="token string">&quot;1&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 0</span>
<span class="token number">1</span> <span class="token operator">*</span> <span class="token string">&quot;10&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 10</span>
<span class="token number">1</span> <span class="token operator">/</span> <span class="token string">&quot;one&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; NaN</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>피연산자를 숫자 타입으로 변환할 수 없는 경우는 산술 연산을 수행할 수 없으므로 표현식의 평가 결과는 <code>NaN</code>이 된다.</p><p>피연산자를 숫자타입으로 변환해야할 문맥은 산술 연산자뿐만이 아니다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token string">&quot;1&quot;</span> <span class="token operator">&gt;</span> <span class="token number">0</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>비교 연산자의 역할은 불리언 값을 만드는 것이다.<br><code>&gt;</code> 비교 연산자는 피연산자의 크기를 비교하므로 피연산자는 코드 문맥상 모두 숫자 타입이어야한다.<br> 비교 연산자의 피연산자 중에서 숫자 타입이 아닌 피연산자를 숫자 타입으로 암묵적 타입 변환한다.</p><p>숫자 타입이 아닌 값을 숫자 타입으로 암묵적 타입 변환을 수행할 때 다음과 같이 동작한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 문자열</span>
<span class="token operator">+</span><span class="token string">&quot;&quot;</span> <span class="token operator">+</span> <span class="token comment">//-&gt; 0</span>
  <span class="token string">&quot;0&quot;</span> <span class="token operator">+</span> <span class="token comment">//-&gt; 0</span>
  <span class="token string">&quot;1&quot;</span> <span class="token operator">+</span> <span class="token comment">//-&gt; 1</span>
  <span class="token string">&quot;string&quot;</span> <span class="token operator">+</span> <span class="token comment">//-&gt; NaN</span>
  <span class="token comment">// 불리언 타입</span>
  <span class="token boolean">true</span> <span class="token operator">+</span> <span class="token comment">//-&gt; 1</span>
  <span class="token boolean">false</span> <span class="token operator">+</span> <span class="token comment">//-&gt; 0</span>
  <span class="token comment">// null 타입</span>
  <span class="token keyword">null</span> <span class="token operator">+</span> <span class="token comment">//-&gt; 0</span>
  <span class="token comment">// undefined 타입</span>
  <span class="token keyword">undefined</span> <span class="token operator">+</span> <span class="token comment">// -&gt; NaN</span>
  <span class="token comment">//객체 타입</span>
  <span class="token punctuation">{</span><span class="token punctuation">}</span> <span class="token operator">+</span> <span class="token comment">//-&gt; NaN</span>
  <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">+</span> <span class="token comment">// -&gt; 0</span>
  <span class="token punctuation">[</span><span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">]</span> <span class="token operator">+</span> <span class="token comment">//-&gt; NaN</span>
  <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; NaN</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>빈 문자열(&#39;&#39;), 빈 배열([]), <code>null</code>, <code>false</code>는 0으로 ,<code>true</code>는 1로 변환된다.<br> 객체와 빈 배열이 아닌 배열, <code>undefined</code>는 변환되지 않아 <code>NaN</code>이 된다.</p><h3 id="_2-3-불리언-타입으로-변환" tabindex="-1"><a class="header-anchor" href="#_2-3-불리언-타입으로-변환" aria-hidden="true">#</a> 2.3. 불리언 타입으로 변환</h3><p>if 문이나 for 문과 같은 제어문 또는 삼항 조건 연산자의 조건식은 불리언 값이 되어야하는 표현식이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token string">&quot;&quot;</span><span class="token punctuation">)</span> console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;1&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span> console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;2&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span> console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;3&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token string">&quot;str&quot;</span><span class="token punctuation">)</span> console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;4&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">null</span><span class="token punctuation">)</span> console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;5&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// 2 4</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>불리언 타입이 아닌 값을 Truthy(참으로 평가) 또는 Falsy(거짓으로 평가)로 구분한다.</p><p>아래는 <code>false</code>로 평가되는 Falsy 값이다.</p><ul><li>false</li><li>undefined</li><li>null</li><li>0, -0</li><li>NaN</li><li>&#39;&#39;(빈 문자열)</li></ul><h2 id="_3-명시적-타입-변환" tabindex="-1"><a class="header-anchor" href="#_3-명시적-타입-변환" aria-hidden="true">#</a> 3. 명시적 타입 변환</h2><p>개발자의 의도에 따라 명시적으로 타입을 변경하는 방법은 다양하다.</p><h3 id="_3-1-문자열-타입으로-변환" tabindex="-1"><a class="header-anchor" href="#_3-1-문자열-타입으로-변환" aria-hidden="true">#</a> 3.1. 문자열 타입으로 변환</h3><ol><li>String 생성자 함수를 new 연산자 없이 호출</li><li>Object.prototype.toString 메서드를 사용</li><li>문자열 연결 연산자를 이용</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">String</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &quot;1&quot;</span>
<span class="token function">String</span><span class="token punctuation">(</span><span class="token number">NaN</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &quot;NaN&quot;</span>
<span class="token function">Stirng</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &quot;true&quot;</span>

<span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &quot;1&quot;</span>
<span class="token number">NaN</span><span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &quot;NaN&quot;</span>
<span class="token boolean">true</span><span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &quot;true&quot;</span>

<span class="token number">1</span> <span class="token operator">+</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &quot;1&quot;</span>
<span class="token number">NaN</span> <span class="token operator">+</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &quot;NaN&quot;</span>
<span class="token boolean">true</span> <span class="token operator">+</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &quot;true&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-2-숫자-타입으로-변환" tabindex="-1"><a class="header-anchor" href="#_3-2-숫자-타입으로-변환" aria-hidden="true">#</a> 3.2. 숫자 타입으로 변환</h3><ol><li>Number 생성자 함수를 new 연산자 없이 호출</li><li>parseInt, parseFloat 함수를 사용 (문자열 -&gt; 숫자)</li><li><code>+</code> 단항 산술 연산자를 이용</li><li><code>*</code> 산술 연산자를 이용</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">Number</span><span class="token punctuation">(</span><span class="token string">&quot;0&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 0</span>
<span class="token function">Number</span><span class="token punctuation">(</span><span class="token string">&quot;10.53&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 10.53</span>
<span class="token function">Number</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 1</span>

<span class="token function">ParseInt</span><span class="token punctuation">(</span><span class="token string">&quot;0&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 0</span>
<span class="token function">ParseInt</span><span class="token punctuation">(</span><span class="token string">&quot;10.53&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 10.53</span>
<span class="token function">ParseInt</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token comment">//-&gt; 1</span>
  <span class="token string">&quot;0&quot;</span> <span class="token operator">+</span> <span class="token comment">//-&gt; 0</span>
  <span class="token string">&quot;10.53&quot;</span> <span class="token operator">+</span> <span class="token comment">//-&gt; 10.53</span>
  <span class="token boolean">true</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 1</span>

<span class="token string">&quot;0&quot;</span> <span class="token operator">*</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 0</span>
<span class="token string">&quot;10.53&quot;</span> <span class="token operator">*</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 10.53</span>
<span class="token boolean">true</span> <span class="token operator">*</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-3-불리언-타입으로-변환" tabindex="-1"><a class="header-anchor" href="#_3-3-불리언-타입으로-변환" aria-hidden="true">#</a> 3.3. 불리언 타입으로 변환</h3><ol><li>Boolean 생성자 함수를 new 연산자 없이 호출</li><li>! 부정 논리 연산자를 두 번 사용</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">Boolean</span><span class="token punctuation">(</span><span class="token string">&quot;x&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt;true</span>
<span class="token function">Boolean</span><span class="token punctuation">(</span><span class="token string">&quot;&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt;false</span>

<span class="token function">Boolean</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
<span class="token function">Boolean</span><span class="token punctuation">(</span><span class="token number">NaN</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
<span class="token function">Boolean</span><span class="token punctuation">(</span><span class="token number">Infinity</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
<span class="token function">Boolean</span><span class="token punctuation">(</span><span class="token keyword">null</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>

<span class="token function">Boolean</span><span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
<span class="token function">Boolean</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>

<span class="token operator">!</span><span class="token operator">!</span><span class="token string">&quot;x&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt;true</span>
<span class="token operator">!</span><span class="token operator">!</span><span class="token string">&quot;&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt;false</span>

<span class="token operator">!</span><span class="token operator">!</span><span class="token number">0</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
<span class="token operator">!</span><span class="token operator">!</span><span class="token number">NaN</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>
<span class="token operator">!</span><span class="token operator">!</span><span class="token number">Infinity</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
<span class="token operator">!</span><span class="token operator">!</span><span class="token keyword">null</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; false</span>

<span class="token operator">!</span><span class="token operator">!</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
<span class="token operator">!</span><span class="token operator">!</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_4-단축-평가" tabindex="-1"><a class="header-anchor" href="#_4-단축-평가" aria-hidden="true">#</a> 4. 단축 평가</h2><h3 id="_4-1-논리-연산자를-사용한-단축-평가" tabindex="-1"><a class="header-anchor" href="#_4-1-논리-연산자를-사용한-단축-평가" aria-hidden="true">#</a> 4.1. 논리 연산자를 사용한 단축 평가</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token string">&quot;Cat&quot;</span> <span class="token operator">&amp;&amp;</span> <span class="token string">&quot;Dog&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &#39;Dog&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>논리곱(&amp;&amp;) 연산자는 두 개의 피연산자 모두 true로 평가될 때 true를 반환한다.<br> 논리곱 연산자는 좌항에서 우항으로 평가가 진행되면서 두 번째 피연산자가 논리 연산의 결과를 결정한다.</p><p>즉 문자열 &#39;Dog&#39;를 그대로 반환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token string">&quot;Cat&quot;</span> <span class="token operator">||</span> <span class="token string">&quot;Dog&quot;</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; &#39;Cat&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>논리합(||) 연산자는 두 개의 피연산자 중 하나만 true로 평가되어도 true를 반환한다.<br> 논리합 연산자는 두 번째 피연산자까지 평가해 보지 않아도 위 표현식을 평가할 수 있다.</p><p>즉 문자열 &#39;Cat&#39;을 그대로 반환한다.</p><p>단축평가는 표현식을 평가하는 도중에 평가 결과가 확정된 경우 나머지 평가 과정을 생략하는 것을 말한다</p><table><thead><tr><th style="text-align:left;">표현식</th><th style="text-align:left;">평가 결과</th></tr></thead><tbody><tr><td style="text-align:left;">true || anything</td><td style="text-align:left;">true</td></tr><tr><td style="text-align:left;">false || anything</td><td style="text-align:left;">anything</td></tr><tr><td style="text-align:left;">true &amp;&amp; anything</td><td style="text-align:left;">anything</td></tr><tr><td style="text-align:left;">false &amp;&amp; anything</td><td style="text-align:left;">false</td></tr></tbody></table><p>단축 평가를 사용하면 if문을 대체할 수 있고, 다음과 같은 상황에서 유용하게 사용된다.</p><ul><li>객체를 가리키기를 기대하는 변수가 null 또는 undefined가 아닌지 확인하고 프로퍼티를 참조</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> elem <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>

<span class="token keyword">var</span> value <span class="token operator">=</span> elem <span class="token operator">&amp;&amp;</span> elem<span class="token punctuation">.</span>value<span class="token punctuation">;</span> <span class="token comment">//-&gt; null</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>함수 매개변수에 기본값을 설정할 때</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">getStringLength</span><span class="token punctuation">(</span><span class="token parameter">str</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  str <span class="token operator">=</span> str <span class="token operator">||</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> str<span class="token punctuation">.</span>length<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token function">getStringLength</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 0</span>
<span class="token function">getStringLength</span><span class="token punctuation">(</span><span class="token string">&quot;hi&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//-&gt; 2</span>

<span class="token comment">// ES6의 매개변수의 기본값 설정</span>
<span class="token keyword">function</span> <span class="token function">getStringLength</span><span class="token punctuation">(</span>str <span class="token operator">=</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> str<span class="token punctuation">.</span>length<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-2-옵셔널-체이닝-연산자" tabindex="-1"><a class="header-anchor" href="#_4-2-옵셔널-체이닝-연산자" aria-hidden="true">#</a> 4.2. 옵셔널 체이닝 연산자</h3><p>ES11(ECMAScript2020)에서 도입된 옵셔널 체이닝 연산자 ?.는<br> 좌항의 피연산자가 null 또는 undefined인 경우 undefined를 반환하고, 그렇지 않으면 우항의 프로퍼티 참조를 이어간다</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> elem <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>

<span class="token keyword">var</span> value <span class="token operator">=</span> elem<span class="token operator">?.</span>value<span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>옵셔널 체이닝 연산자가 도입되기 이전에는 논리 연산자 &amp;&amp;을 사용하여 변수가 null 또는 undefined인지 확인했다.</p><h3 id="_4-3-null-병합-연산자" tabindex="-1"><a class="header-anchor" href="#_4-3-null-병합-연산자" aria-hidden="true">#</a> 4.3. null 병합 연산자</h3><p>ES11(ECMAScript2020)에서 도입된 null 병합 연산자 ??는<br> 좌항의 피연산자가 null 또는 undefined인 경우 우항의 피연사자를 반환하고, 그렇지 않으면 좌항의 피연산자를 반환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> foo <span class="token operator">=</span> <span class="token keyword">null</span> <span class="token operator">??</span> <span class="token string">&quot;default string&quot;</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// &#39;default string&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div>`,62),o=[p];function c(l,i){return s(),a("div",null,o)}const d=n(e,[["render",c],["__file","deepdive9.html.vue"]]);export{d as default};
